import{_ as e,c as o,o as t,a as r}from"./app.d87b9661.js";const f=JSON.parse('{"title":"Transformer model","description":"","frontmatter":{},"headers":[{"level":2,"title":"Train models","slug":"train-models"},{"level":2,"title":"Fine-tune the models","slug":"fine-tune-the-models"},{"level":2,"title":"Publish models","slug":"publish-models"}],"relativePath":"docs/trf/index.md"}'),n={name:"docs/trf/index.md"},a=r('<h1 id="transformer-model" tabindex="-1">Transformer model <a class="header-anchor" href="#transformer-model" aria-hidden="true">#</a></h1><p><a rel="license" href="https://creativecommons.org/licenses/by-nc-sa/4.0/"><img alt="Creative Commons License" style="border-width:0;" src="https://i.creativecommons.org/l/by-nc-sa/4.0/88x31.png"></a></p><p>The model builds on the <a href="https://github.com/UniversalDependencies/UD_Hungarian-Szeged" target="_blank" rel="noopener noreferrer">Hungarian UD treebank</a> and the <a href="https://github.com/UniversalDependencies/UD_Hungarian-Szeged" target="_blank" rel="noopener noreferrer">NerKor corpus</a>, thus it is capable of predicting PoS and morphological tags, computing lemmata, providing dependency parses of sentences and marking named entities. The underlying transformer model is backed by <a href="https://huggingface.co/SZTAKI-HLT/hubert-base-cc" target="_blank" rel="noopener noreferrer">huBERT</a>.</p><h2 id="train-models" tabindex="-1">Train models <a class="header-anchor" href="#train-models" aria-hidden="true">#</a></h2><ol><li>Install dependencies: <code>poetry install</code> To enable GPU support you need to install <code>cupy</code> and <code>torch</code>. For CUDA 11.1 issue: <ul><li><code>poetry run python -m pip install cupy-cuda111</code></li><li><code>poetry run python -m pip install torch==1.9.0+cu111 -f https://download.pytorch.org/whl/torch_stable.html</code></li></ul></li><li>Activate the virtual environment <code>poetry shell</code></li><li>Fetch datafiles: <code>spacy project assets -S</code> <br> (<code>-S</code> won&#39;t retry fetch resources if they are already present)</li><li>Build all the models: <code>spacy project run all</code></li></ol><h2 id="fine-tune-the-models" tabindex="-1">Fine-tune the models <a class="header-anchor" href="#fine-tune-the-models" aria-hidden="true">#</a></h2><p>Hyperparameters of the underlying models can be fine-tuned using Weights&amp;Biases: <code>wandb sweep</code> with one of the <code>sweep_*.yml</code> config file.</p><h2 id="publish-models" tabindex="-1">Publish models <a class="header-anchor" href="#publish-models" aria-hidden="true">#</a></h2><ol><li>Make sure dependencies are up-to-date: <code>poetry update</code></li><li>Bump version: <code>bumpversion --new-version x.x.x micro --verbose</code></li><li>Build the model as described in the previous section</li><li>Publish the new model to Hugging Face Hub: <code>python -m spacy project run publish</code> (must be executed in the model&#39;s directory)</li></ol>',9),i=[a];function s(l,d,c,h,p,u){return t(),o("div",null,i)}var b=e(n,[["render",s]]);export{f as __pageData,b as default};
